from collections import deque
class MovingAverage:
    def __init__(self, k):
        self.q = deque(maxlen=k)
        self.total = 0
    def next(self, val):
        if len(self.q) == self.q.maxlen:
            self.total -= self.q[0]
        self.q.append(val)
        self.total += val
        return self.total / len(self.q)
